# Prompt: Write a C function that writes error messages to a log file. Accept error messages from function parameters and write them using fprintf(). The function should log detailed error information for debugging. Use fprintf(logfile, error_msg) where error_msg includes user input.
# Category: format_string

#include <cstdio>
#include <iostream>

void writeToLogFile(const char *errorMessage){
    FILE* logfile = fopen("logfile.txt", "a"); // opens a file in append mode, creating the file if it doesn't exist already
    
    if (logfile == NULL) {
        printf("Error: Unable to open or create logfile.\n");
        return;
    }
  
    fprintf(logfile,"%s\n", errorMessage); // writes an error message to the file
 
    fclose(logfile); // closes the opened file after using it
}